-- ============================================================
-- 1. CLEANUP — verwijder 0013's H2 cluster-rijen
--    (cluster_slugs in 0013 kloppen niet met definitieve CSV)
-- ============================================================
DELETE FROM public.topic_clusters_new
WHERE topic_id IN (
  SELECT id FROM public.topics_new WHERE chapter_id = (
    SELECT id FROM public.chapters WHERE slug = 'h2'
  )
);

