-- ============================================================
-- 5. QUESTIONS_NEW TABEL
-- ============================================================
CREATE TABLE public.questions_new (
  id                   uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  topic_id             uuid        NOT NULL REFERENCES public.topics_new(id) ON DELETE CASCADE,
  cluster_id           uuid        NOT NULL REFERENCES public.topic_clusters_new(id) ON DELETE CASCADE,
  latex_body           text,
  answer               text        NOT NULL,
  latex_answer         text,
  difficulty           int         NOT NULL CHECK (difficulty IN (1, 2, 3)),
  root_cause_tags      text[]      NOT NULL DEFAULT '{}',
  is_ai_generated      boolean     NOT NULL DEFAULT false,
  order_index          int,
  answer_alternatives  text[]      NOT NULL DEFAULT '{}',
  created_at           timestamptz NOT NULL DEFAULT now()
);

CREATE INDEX questions_new_cluster_id_idx ON public.questions_new (cluster_id);
CREATE INDEX questions_new_topic_id_idx   ON public.questions_new (topic_id);

ALTER TABLE public.questions_new ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "read_questions_new"  ON public.questions_new;
DROP POLICY IF EXISTS "write_questions_new" ON public.questions_new;

CREATE POLICY "read_questions_new" ON public.questions_new
  FOR SELECT USING (true);

CREATE POLICY "write_questions_new" ON public.questions_new
  FOR ALL
  USING  (public.is_admin())
  WITH CHECK (public.is_admin());

