-- ============================================================
-- 7. QUESTION_STEPS_NEW TABEL
-- ============================================================
CREATE TABLE public.question_steps_new (
  id               uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  question_id      uuid NOT NULL REFERENCES public.questions_new(id) ON DELETE CASCADE,
  step_order       int  NOT NULL,
  step_description text NOT NULL,
  UNIQUE (question_id, step_order)
);

CREATE INDEX question_steps_new_question_id_idx ON public.question_steps_new (question_id);

ALTER TABLE public.question_steps_new ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "read_question_steps_new"  ON public.question_steps_new;
DROP POLICY IF EXISTS "write_question_steps_new" ON public.question_steps_new;

CREATE POLICY "read_question_steps_new" ON public.question_steps_new
  FOR SELECT USING (true);

CREATE POLICY "write_question_steps_new" ON public.question_steps_new
  FOR ALL
  USING  (public.is_admin())
  WITH CHECK (public.is_admin());

