  ('h2_quotientregel', 'polynoom_breuk', 2, 4, 'Vereenvoudig: $f''(x) = \dfrac{-12x}{(2x^2+1)^2}$.'),
  ('h2_quotientregel', 'polynoom_breuk', 3, 1, 'Benoem: $t(x) = x^3$ en $n(x) = 2x^2 + 1$.'),
  ('h2_quotientregel', 'polynoom_breuk', 3, 2, 'Bepaal de afgeleiden: $t''(x) = 3x^2$ en $n''(x) = 4x$.'),
  ('h2_quotientregel', 'polynoom_breuk', 3, 3, 'Pas de quotiëntregel toe: $f''(x) = \dfrac{3x^2(2x^2+1) - x^3 \cdot 4x}{(2x^2+1)^2}$.'),
  ('h2_quotientregel', 'polynoom_breuk', 3, 4, 'Laat in deze vorm staan zoals het boek doet.'),
  ('h2_quotientregel', 'polynoom_breuk', 4, 1, 'Benoem: $t(x) = x^4$ en $n(x) = x^2 + 1$.'),
  ('h2_quotientregel', 'polynoom_breuk', 4, 2, 'Bepaal de afgeleiden: $t''(x) = 4x^3$ en $n''(x) = 2x$.'),
  ('h2_quotientregel', 'polynoom_breuk', 4, 3, 'Pas de quotiëntregel toe: $f''(x) = \dfrac{4x^3(x^2+1) - x^4 \cdot 2x}{(x^2+1)^2}$.'),
  ('h2_quotientregel', 'polynoom_breuk', 4, 4, 'Laat in deze vorm staan zoals het boek doet.'),
  ('h2_quotientregel', 'polynoom_breuk', 5, 1, 'Benoem: $t(x) = x - 2$ en $n(x) = 3 - x^2$.'),
  ('h2_quotientregel', 'polynoom_breuk', 5, 2, 'Bepaal de afgeleiden: $t''(x) = 1$ en $n''(x) = -2x$.'),
  ('h2_quotientregel', 'polynoom_breuk', 5, 3, 'Pas de quotiëntregel toe: $f''(x) = \dfrac{1 \cdot (3-x^2) - (x-2)(-2x)}{(3-x^2)^2}$.'),
  ('h2_quotientregel', 'polynoom_breuk', 5, 4, 'Laat in deze vorm staan.'),
  ('h2_quotientregel', 'polynoom_breuk', 6, 1, 'De variabele heet $t$. Benoem: $T(t) = t^2 + 1$ en $N(t) = t^3 - t$.'),
  ('h2_quotientregel', 'polynoom_breuk', 6, 2, 'Bepaal de afgeleiden: $T''(t) = 2t$ en $N''(t) = 3t^2 - 1$.'),
  ('h2_quotientregel', 'polynoom_breuk', 6, 3, 'Pas de quotiëntregel toe: $g''(t) = \dfrac{2t(t^3-t) - (t^2+1)(3t^2-1)}{(t^3-t)^2}$.'),
  ('h2_quotientregel', 'polynoom_breuk', 6, 4, 'Laat in deze vorm staan.'),
  ('h2_quotientregel', 'som_met_breuk', 1, 1, 'Splits met de somregel: $f(x) = g(x) + h(x)$ met $g(x) = x^2$ en $h(x) = -\dfrac{3}{x+1}$.'),
  ('h2_quotientregel', 'som_met_breuk', 1, 2, '$g''(x) = 2x$. Voor $h(x)$ pas je de quotiëntregel toe met $t(x) = -3$, $n(x) = x+1$, dus $t''(x) = 0$ en $n''(x) = 1$.'),
  ('h2_quotientregel', 'som_met_breuk', 1, 3, 'Bereken $h''(x) = \dfrac{0 \cdot (x+1) - (-3) \cdot 1}{(x+1)^2} = \dfrac{3}{(x+1)^2}$.'),
  ('h2_quotientregel', 'som_met_breuk', 1, 4, 'Combineer: $f''(x) = 2x + \dfrac{3}{(x+1)^2}$.'),
  ('h2_quotientregel', 'som_met_breuk', 2, 1, 'Splits met de somregel: $g(x) = x^2$ en $h(x) = -\dfrac{2}{x+4}$.'),
  ('h2_quotientregel', 'som_met_breuk', 2, 2, '$g''(x) = 2x$. Voor $h(x)$: $t(x) = -2$, $n(x) = x+4$, $t''(x) = 0$, $n''(x) = 1$.'),
  ('h2_quotientregel', 'som_met_breuk', 2, 3, 'Bereken $h''(x) = \dfrac{0 - (-2) \cdot 1}{(x+4)^2} = \dfrac{2}{(x+4)^2}$.'),
  ('h2_quotientregel', 'som_met_breuk', 2, 4, 'Combineer: $f''(x) = 2x + \dfrac{2}{(x+4)^2}$.'),
  ('h2_quotientregel', 'som_met_breuk', 3, 1, 'Splits met de somregel: $g(x) = 3x$ en $h(x) = \dfrac{1}{x-1}$.'),
  ('h2_quotientregel', 'som_met_breuk', 3, 2, '$g''(x) = 3$. Voor $h(x)$: $t(x) = 1$, $n(x) = x-1$, $t''(x) = 0$, $n''(x) = 1$.'),
  ('h2_quotientregel', 'som_met_breuk', 3, 3, 'Bereken $h''(x) = \dfrac{0 - 1 \cdot 1}{(x-1)^2} = \dfrac{-1}{(x-1)^2}$.'),
  ('h2_quotientregel', 'som_met_breuk', 3, 4, 'Combineer: $f''(x) = 3 - \dfrac{1}{(x-1)^2}$.'),
  ('h2_quotientregel', 'som_met_breuk', 4, 1, 'Splits met de somregel: $g(x) = \dfrac{3-x^2}{x-2}$ en $h(x) = x^3$.'),
  ('h2_quotientregel', 'som_met_breuk', 4, 2, 'Voor $g(x)$: $t(x) = 3-x^2$, $n(x) = x-2$, $t''(x) = -2x$, $n''(x) = 1$.'),
  ('h2_quotientregel', 'som_met_breuk', 4, 3, 'Pas de quotiëntregel toe: $g''(x) = \dfrac{-2x(x-2) - (3-x^2) \cdot 1}{(x-2)^2}$.'),
  ('h2_quotientregel', 'som_met_breuk', 4, 4, '$h''(x) = 3x^2$. Combineer: $f''(x) = \dfrac{-2x(x-2) - (3-x^2)}{(x-2)^2} + 3x^2$.'),
  ('h2_quotientregel', 'som_met_breuk', 5, 1, 'Splits met de somregel: $g(x) = x^3$ en $h(x) = \dfrac{2x+1}{x-3}$.'),
  ('h2_quotientregel', 'som_met_breuk', 5, 2, '$g''(x) = 3x^2$. Voor $h(x)$: $t(x) = 2x+1$, $n(x) = x-3$, $t''(x) = 2$, $n''(x) = 1$.'),
  ('h2_quotientregel', 'som_met_breuk', 5, 3, 'Pas de quotiëntregel toe: $h''(x) = \dfrac{2(x-3) - (2x+1) \cdot 1}{(x-3)^2} = \dfrac{2x-6-2x-1}{(x-3)^2} = \dfrac{-7}{(x-3)^2}$.'),
  ('h2_quotientregel', 'som_met_breuk', 5, 4, 'Combineer: $f''(x) = 3x^2 + \dfrac{-7}{(x-3)^2}$.'),
  ('h2_quotientregel', 'som_met_breuk', 6, 1, 'De variabele is $q$. Splits: $g(q) = q^2$ en $h(q) = -\dfrac{q+1}{2q-1}$.'),
  ('h2_quotientregel', 'som_met_breuk', 6, 2, '$g''(q) = 2q$. Voor $h(q)$: $t(q) = q+1$, $n(q) = 2q-1$, $t''(q) = 1$, $n''(q) = 2$.'),
  ('h2_quotientregel', 'som_met_breuk', 6, 3, 'Pas de quotiëntregel toe: $\left[\dfrac{q+1}{2q-1}\right]'' = \dfrac{1(2q-1) - (q+1) \cdot 2}{(2q-1)^2} = \dfrac{2q-1-2q-2}{(2q-1)^2} = \dfrac{-3}{(2q-1)^2}$.'),
  ('h2_quotientregel', 'som_met_breuk', 6, 4, 'Met het minteken voor $h$ wordt het: $h''(q) = -\dfrac{-3}{(2q-1)^2} = \dfrac{3}{(2q-1)^2}$. Combineer: $h''(q) = 2q + \dfrac{3}{(2q-1)^2}$.')
) AS s(topic_slug, cluster_slug, q_order, step_order, description)
JOIN public.topics_new t          ON t.slug    = s.topic_slug
JOIN public.topic_clusters_new tc ON tc.slug   = s.cluster_slug AND tc.topic_id = t.id
JOIN public.questions_new q       ON q.cluster_id = tc.id AND q.order_index = s.q_order;

-- ============================================================
-- 9. VALIDATIE
-- ============================================================
SELECT 'chapters'           AS tbl, COUNT(*)::text AS n FROM public.chapters
UNION ALL
SELECT 'topics_new',          COUNT(*)::text FROM public.topics_new
UNION ALL
SELECT 'topic_clusters_new',  COUNT(*)::text FROM public.topic_clusters_new
UNION ALL
SELECT 'questions_new',       COUNT(*)::text FROM public.questions_new
UNION ALL
SELECT 'question_steps_new',  COUNT(*)::text FROM public.question_steps_new;
-- Verwacht: chapters=4, topics_new=10, topic_clusters_new=37, questions_new=219, question_steps_new=184

SELECT c.slug AS chapter, COUNT(q.id) AS questions
FROM public.chapters c
JOIN public.topics_new t      ON t.chapter_id = c.id
JOIN public.questions_new q   ON q.topic_id = t.id
